import hashlib
import hmac
import secrets

def hash_password(password):
    """Hashes a password using SHA-256 and HMAC."""
    salt = secrets.token_bytes(16)
    hashed_password = hmac.new(salt, password.encode(), hashlib.sha256).digest()
    return salt + hashed_password

def verify_password(stored_hash, provided_password):
    """Verifies a provided password against the stored hash."""
    salt = stored_hash[:16]
    expected_hash = hmac.new(salt, provided_password.encode(), hashlib.sha256).digest()
    return hmac.compare_digest(stored_hash[16:], expected_hash)

